Here's an example of integrating the C1 API and GenUI SDK in a Next.js app. First, configure the client to point to Thesys's endpoint, then fetch a UI spec and render it using the `<C1Component>`:

javascript
import { C1Component, ThemeProvider } from "@thesys/genui-sdk";

const App = async () => {
  // Fetch UI spec from the C1 API
  const response = await fetch("https://api.thesys.dev/v1/embed", {
    method: "POST",
    headers: {"Content-Type": "application/json"},
    body: JSON.stringify({
      model: "c1-nightly",
      messages: [{role: "user", content: "Show me a balance chart and a currency selector."}],
    }),
  });
  const uiSpec = await response.json();

  return (
    <ThemeProvider>
      <C1Component c1Response={uiSpec} />
    </ThemeProvider>
  );
};

export default App;
